### Instruction:
Create a React application to search for movies from IMDB API.
The application should have an input field to enter the keyword for search and should display the list of matched movies along with the movie titles, release year, and rating.

### Response:
import React, { useState, useEffect } from "react";
import axios from "axios";

const App = () => {
 const [query, setQuery] = useState("");
 const [movies, setMovies] = useState([]);

 useEffect(() => {
 const fetchMovies = () => {
  axios
   .get(`http://www.omdbapi.com/?i=tt3896198&apikey=xxxxxx&s=${query}`)
   .then(res => {
    setMovies(res.data.Search);
   })
   .catch(err => {
    throw new Error(err);
   });
  };
  fetchMovies();
 }, [query]);

 const handleChange = e => {
  setQuery(e.target.value);
 };

 return (
  <div>
   <input type="text" value={query} onChange={handleChange} />
   {movies.map(movie => {
    return (
     <div>
      <h2>{movie.Title}</h2>
      <p>Released in {movie.Year}</p>
      <p>Rating: {movie.imdbRating}</p>
     </div>
    );
   })}
  </div>
 );
};

export default App;

