### Instruction:
Write a function to evaluate simple arithmetic expression and return the result.

### Response:
def evaluate_expression(expression):
    expression = expression.replace(" ", "")
    if "/" in expression:
        first_number, operator, second_number = expression.split("/")
        return float(first_number) / float(second_number)
    elif "*" in expression:
        first_number, operator, second_number = expression.split("*")
        return float(first_number) * float(second_number)
    elif "+" in expression:
        first_number, operator, second_number = expression.split("+")
        return float(first_number) + float(second_number)
    elif "-" in expression:
        first_number, operator, second_number = expression.split("-")
        return float(first_number) - float(second_number)

