### Instruction:
Create a function in Java to print out the Fibonacci sequence.

### Response:
public class Fibonacci {

    public static void printFibonacci(int n) {
        int sum = 0;
        int prev = 0;
        int current = 1;
        System.out.print(prev + " ");
        System.out.print(current + " ");

        for (int i = 2; i < n; i++) {
            sum = prev + current;
            prev = current;
            current = sum;
            System.out.print(sum + " ");
        }
        System.out.println();
    }

    public static void main(String[] args) {
        int n = 10;
        printFibonacci(n);
    }
}

### Instruction:
Create a React Native application for a shopping cart. This application should contain components for viewing the cart and adding items to the cart.

### Response:
import React, { useState } from 'react';
import { StyleSheet, View, Text } from 'react-native';

const App = () => {
  const [items, setItems] = useState([]);

  const addItem = (item) => {
    setItems([...items, item]);
  };

  const removeItem = (item) => {
    const updatedItems = items.filter((i) => i != item);
    setItems(updatedItems);
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Shopping Cart</Text>
      <View style={styles.items}>
        {items.map((item, index) => (
          <View key={index} style={styles.item}>
            <Text>{item}</Text>
            <Text onPress={() => removeItem(item)}>Remove</Text>
          </View>
        ))}
      </View>
      <Text style={styles.title}>Add Item</Text>
      <TextInput onSubmitEditing={(event) => addItem(event.nativeEvent.text)} />
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    alignItems: 'center',
    justifyContent: 'center',
  },
  title: {
    fontSize: 24,
    fontWeight: '500',
    textAlign: 'center',
    marginVertical: 10,
  },
  items: {
    marginVertical: 10,
  },
  item: {
    padding: 10,
    marginVertical: 5,
    borderWidth: 1,
    borderColor: 'lightgray',
    borderRadius: 5,
  },
});

export default App;

### Instruction:
Create a basic React component to render a form with multiple input fields and a Submit button.

### Response:
import React, { Component } from 'react';

class MyForm extends Component {
 constructor(props) {
 super(props);
 this.state = {
 name: '',
 email: '',
 message: ''
 };

 this.handleInputChange = this.handleInputChange.bind(this);
 this.handleSubmit = this.handleSubmit.bind(this);
 }

 handleInputChange(event) {
 const target = event.target;
 const value = target.value;
 const name = target.name;

 this.setState({
 [name]: value
 });
 }

 handleSubmit(event) {
 event.preventDefault();
 alert('Form submitted! Name: ' + this.state.name + ', Email: ' + this.state.email + ', Message: ' + this.state.message);
 }

 render() {
 return (
 <form onSubmit={this.handleSubmit}>
 <label>
 Name:
 <input type="text" name="name" value={this.state.name} onChange={this.handleInputChange} />
 </label>
 <label>
 Email:
 <input type="text" name="email" value={this.state.email} onChange={this.handleInputChange} />
 </label>
 <label>
 Message:
 <textarea name="message" value={this.state.message} onChange={this.handleInputChange} />
 </label>
 <input type="submit" value="Submit" />
 </form>
 );
 }
}

export default MyForm;

