### Instruction:
Write a JavaScript program to find the elements in a given array which have a minimum difference between the next elements.

### Response:
function minDiffArray(arr) { 
    let min = arr[1] - arr[0]; 

    for (let i = 0; i < arr.length - 1; i++) { 
        let diff = arr[i+1] - arr[i]; 
        if (diff < min) {
            min = diff; 
        }
     } 

     return min;
}

