### Instruction:
Create an algorithm to calculate the total number of permutations of a given string with the given size.

### Response:
#include <iostream>
#include <string>

using namespace std;

// Function to calculate total number of permutations 
// of a string with given size 
int findPermutation(string s, int n) 
{ 
	int f = 1; 

	// Calculate n! 
	for (int i = 1; i <= n; i++) 
		f *= i; 

	// Calculate nCr for each character 
	for (int i = 0; s[i] != '\0'; i++) 
	{ 
		int count = 1; 
		for (int j = i + 1; s[j] != '\0'; j++) 
			if (s[i] == s[j]) 
				count++; 

		// Find nCr and store it in f  
		f = f / (count * (count - n)); 
	} 
	return f; 
} 

int main() 
{ 
    string s = "abc";
    int n = 2;
    cout << findPermutation(s, n);
	return 0; 
}

