        return this.age == otherStudent.getAge();
    }
}

### Instruction:
Generate a program which implements the Huffman Coding algorithm.

### Response:
def HuffmanCoding(char_freq):
	node_queue = []  # minimum heap, binary

	for key in char_freq: 
		node_queue.append(Node(key=key, freq=char_freq[key]))

	while (len(node_queue) > 1):
		node_1 = node_queue.pop(0) 
		node_2 = node_queue.pop(0) 

		freq_sum = node_1.freq + node_2.freq
		node_queue.append(Node(left=node_1, right=node_2, freq=freq_sum))

	return node_queue.pop(0)

