Generate a code to implement a C++ program to find the mode of an array of integers.

### Response:
"""
Implement a C++ program to find the mode of an array of integers
"""

#include <iostream>
#include <map>

// Define the array
int arr[] = {4, 2, 8, 6, 4, 8};

// Create a map to store the data
std::map<int, int> data;

// Iterate through the array and store the count of each element
for(int i = 0; i < 6; i++)
{
    if(data.find(arr[i]) != data.end())
    {
        data[arr[i]]++;
    }
    else
    {
        data[arr[i]] = 1;
    }
}

// Initialize max count to minimum
int max_count = 0;

// Initialize mode to an invalid number
int mode = -1;

// Iterate through the map and find the element with the maximum count
for(auto itr = data.begin(); itr != data.end(); itr++)
{
    if(itr->second > max_count)
    {
        max_count = itr->second;
        mode = itr->first;
    }
}

// Print the mode of the array
std::cout << "Mode of the array is: " << mode << std::endl;

