Develop an algorithm for optimizing the routing of deliveries in a city.

### Response:
def optimization_algorithm(G, n):

  # Initialize the minimum-cost paths for all vertex pairs 
  dist = [[float("inf") for i in range(n)] for j in range(n)] 

  for i in range(n): 
      dist[i][i] = 0

  # Process all edges  
  for u, v, w in G: 
      dist[u][v] = w

  # Shortest paths using Floyd Warshall Algorithm 
  for k in range(n): 
      for i in range(n): 
        for j in range(n): 
            dist[i][j] = min(dist[i][j], dist[i][k]+ dist[k][j] ) 

  # Print all shortest distances
  print ("The following matrix shows the shortest distances between every pair of vertices:")
  for i in range(n): 
      for j in range(n): 
        if(dist[i][j] == float("inf")): 
            print ("INF", end=" ")
        else: 
            print (dist[i][j], end="  ") 
        if j == n-1: 
            print (" ") 

  return dist

