using System;
using System.Collections.Generic;

class Primes
{
    public static List<int> GetPrimes() {
        List<int> primes = new List<int>();
        int num = 2;

        while (primes.Count < 25) {
            if (IsPrime(num))
                primes.Add(num);

            num++;
        }

        return primes;
    }

