$str = "abc";

function permutation($str) {
	$length = strlen($str);
	if ($length == 1) {
		return [$str];
	}

	$perm = permutation(substr($str, 1));
	$first = substr($str, 0, 1);
	$result = array();

	foreach ($perm as $p) {
		$size = strlen($p);
		for ($i = 0; $i <= $size; $i++) {
			$s = substr($p, 0, $i) . $first . substr($p, $i);
			$result[] = $s;
		}
	}

	return $result;
}

