### Instruction:
Implement an alogrithm to reverse a linked list

### Response:
/**
  * Definition for singly-linked list.
  * struct ListNode {
  *     int val;
  *     ListNode *next;
  *     ListNode(int x) : val(x), next(NULL) {}
  * };
  */

ListNode* reverseList(ListNode* head) 
{ 
    // Base case 
    if (head == NULL || head->next == NULL) 
        return head; 

    // Reverse the rest of the list 
    ListNode* reversedList = reverseList(head->next); 

    // Put head element at the end 
    head->next->next = head; 

    // Detach head element from the list 
    head->next = NULL; 

    return reversedList; 
}

