### Instruction:
Build a blockchain system that can handle various transactions.

### Response:
// create a Block class
class Block {
  constructor(index, transaction, previousHash = '') {
    this.index = index;
    this.timestamp = new Date();
    this.transaction = transaction;
    this.previousHash = previousHash;
    this.hash = this.calculateHash();
  }
  calculateHash() {
    return sha256(this.index + this.previousHash + this.timestamp + JSON.stringify(this.transaction)).toString();
  }
}

// create the Blockchain class
class Blockchain{
  constructor() {
    this.chain = [this.createGenesisBlock()];
  }
  createGenesisBlock() {
    return new Block(0, { amount: 0 }, "0");
  }
  getLatestBlock(){
    return this.chain[this.chain.length - 1];
  }
  addBlock(newBlock){
    newBlock.previousHash = this.getLatestBlock().hash;
    newBlock.hash = newBlock.calculateHash();
    this.chain.push(newBlock);
  }
  isChainValid() {
    for (let i = 1; i < this.chain.length; i++){
      const currentBlock = this.chain[i];
      const previousBlock = this.chain[i - 1];
      if (currentBlock.hash !== currentBlock.calculateHash()) {
        return false;
      }
      if (currentBlock.previousHash !== previousBlock.hash) {
        return false;
      }
    }
    return true;
  }
}

