        node1.addNeighbors(node2);
        node1.addNeighbors(node3);
        node2.addNeighbors(node4);
        node2.addNeighbors(node5);
        node3.addNeighbors(node6);
        node3.addNeighbors(node7);

        return node1;
    }

    // Main method
    public static void main(String[] args) {
        Node node1 = createGraph();
        bfs(node1);
    }

}

