### Instruction:
Design a C# program that takes two strings and checks if the characters in the first string form a subsequence of the characters in the second string.

### Response:
public class Program
{
    public static bool IsSubSequence(string s1, string s2) 
    {
        int m = s1.Length; 
        int n = s2.Length; 

        int j = 0;

        for (int i = 0; i < n && j < m; i++) 
            if (s1[j] == s2[i]) 
                j++; 

        return (j == m); 
    } 
    public static void Main() 
    { 
        string s1 = "AXY"; 
        string s2 = "ADXCPY"; 

        if (IsSubSequence(s1, s2)) 
            Console.Write("Yes"); 
        else
            Console.Write("No"); 
    } 
}

