Create a web page with React that shows a list of books and shows detailed information about each book when clicked.

### Response:
import React from 'react';
import Books from './Books';

class App extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      books: [],
      selectedBook: null,
    };
  }

  // get books data
  componentDidMount() {
    fetch('/books.json')
      .then(response => response.json())
      .then(data => {
        this.setState({
          books: data,
        });
      })
      .catch(err => console.error(err));
  }

  // set selected book
  setBook = selectedBook => {
    this.setState({
      selectedBook,
    });
  }

  render() {
    const { books, selectedBook } = this.state;
    return (
      <div>
        <Books
          books={ books }
          setBook={ this.setBook }
        />
        {selectedBook && <p>Title: {selectedBook.title}</p>}
        {selectedBook && <p>Author: {selectedBook.author}</p>}
      </div>
    )
  }
}

export default App;

